Action.ExecScriptExpression:
using System;
using System.Drawing;
using System.Linq;
using System.Threading;
using System.Windows.Forms;
using Triggernometry.Core;
using Triggernometry.UI.CustomControls;
using Triggernometry.UI.Forms;
using static Triggernometry.UI.Forms.GameConfigForm;

// 注册回调
RealPlugin.Instance.RegisterNamedCallback(VcEntry.Info.ConfigName, new Action<object, string>((_, __) => VcEntry.Start()), null);

public static class VcEntry
{
    // 配置信息定义
    public static ConfigInfo Info = new ConfigInfo("异闻迷宫宝宝椅", "3.0", "阿洛", "V&C_cfg");

    public static void RunConfigForm()
    {
        try { _RunConfigForm(); }
        catch (Exception ex)
        {
            MessageBox.Show("配置界面运行时遇到问题：\n\n" + ex, Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private static void _RunConfigForm()
    {
        GameConfigForm form = new GameConfigForm(Info);
        form.Shown += (sender, e) => RealPlugin.Instance.InvokeNamedCallback("command", "/e <se.9>");

        BijectDictionary<string, string> cbxItems;
        Option optionCtrl;

        // --- 倒序添加选项组 ---

        #region 配置：7.4 商客奇谭
        OptionsTableLayoutPanel table_v7a = form.AddOptionGroup(" 7.4 商客奇谭 ");
        form.AddLabel("　", table_v7a);
        #endregion

        #region 配置：6.5 Aloalo Island
        OptionsTableLayoutPanel table_v6c = form.AddOptionGroup(" 6.5 阿罗阿罗岛 ");
        cbxItems = new BijectDictionary<string, string>(
            ("南北", " 南北式（推荐）"),
            ("排队", " 排队式"),
            ("融合", " 融合式")
        );
        form.AddOption(new OptionCbx("Boss 1 开场水晶机制攻略选择", "vc65_1_crStrat", cbxItems, "南北",
            "攻略中的三种站位方式。每种攻略下都可以正确播报自己应该去的位置。\n\n" +
            "南北式：T远固定北半场，H近固定南半场。\n" +
            "强烈推荐此攻略，和文本播报完美兼容。\n" +
            "全队完全不需要思考，照抄站位即可。"), table_v6c);
        #endregion

        #region 配置：6.4 六根山
        OptionsTableLayoutPanel table_v6b = form.AddOptionGroup(" 6.4 六根山 ");
        cbxItems = new BijectDictionary<string, string>(
            ("diagNear", " 斜方向，靠近场中"),
            ("diagFar", " 斜方向，贴角落"),
            ("vertical", " 正南北，贴边")
        );
        form.AddOption(new OptionCbx("Boss 3 赤帝空闪刃拉线", "vc64_3_fire", cbxItems, "vertical",
            "Boss 3 怨灵猛虎：\n赤帝空闪刃（火线）机制中，连线点名引导面向的位置"), table_v6b);
        #endregion

        #region 配置：6.2 希拉狄哈水道
        OptionsTableLayoutPanel table_v6a = form.AddOptionGroup(" 6.2 希拉狄哈水道 ");
        cbxItems = new BijectDictionary<string, string>(("0", " 禁止"), ("1", " 允许"));
        form.AddOption(new OptionCbx("是否允许未来观测（预报安全区）", "vc62_allowPredict", cbxItems, "0",
            "在以下机制中预报安全区：\n\n · 擦拭：左右半场\n · 刚武突/旋击：充能层数"), table_v6a);
        #endregion

        #region 配置：文本频道
        OptionsTableLayoutPanel tableChannel = form.AddOptionGroup(" 文本频道 ");
        var cnlPublicItems = new BijectDictionary<string, string>(
            ("", " （禁用）"), ("p", " 小队"), ("e", " 默语"), ("fc", " 部队"),
            ("l1", " 通讯贝1"), ("l2", " 通讯贝2"), ("l3", " 通讯贝3"), ("l4", " 通讯贝4"),
            ("l5", " 通讯贝5"), ("l6", " 通讯贝6"), ("l7", " 通讯贝7"), ("l8", " 通讯贝8"),
            ("cwl1", " 跨服通讯贝1"), ("cwl2", " 跨服通讯贝2"), ("cwl3", " 跨服通讯贝3"), ("cwl4", " 跨服通讯贝4"),
            ("cwl5", " 跨服通讯贝5"), ("cwl6", " 跨服通讯贝6"), ("cwl7", " 跨服通讯贝7"), ("cwl8", " 跨服通讯贝8")
        );
        var cnlDebugItems = cnlPublicItems.ShallowCopy();
        cnlDebugItems.RemoveKey("p");
        var cnlPrivateItems = cnlDebugItems.ShallowCopy();
        cnlPrivateItems.RemoveKey("");

        form.AddOption(new OptionCbx("公共频道", "cnlPublic", cnlPublicItems, "e",
            "本频道用于播报部分机制、示意图、复盘信息等机制相关内容。\n\n默认设为自己可见的默语频道，\n如有需要可设为小队等。"), tableChannel);

        form.AddOption(new OptionCbx("个人频道", "cnlPrivate", cnlPrivateItems, "e",
            "本频道用于发送仅应自己可见的系统提示消息。\n\n本项设置不应选择任何其他人可见的频道。"), tableChannel);

        form.AddOption(new OptionCbx("调试频道", "cnlDebug", cnlDebugItems, "",
            "本频道用于发送调试信息。\n\n如果你在参与测试，请设置为自己可见的频道。\n\n如果你不知道什么叫调试，就不要开启。"), tableChannel);

        form.AddOption(new OptionCbx("复活记录频道（开发中）", "cnlRes", cnlPublicItems, "e",
            "本频道用于异闻难度下队友死亡时提示谁还有复活。"), tableChannel);
        #endregion

        #region 使用说明
        OptionsTableLayoutPanel table_desc = form.AddOptionGroup(" 使用说明 ");
        var lbl = form.AddLabel("若有疑问，请查阅此触发器分组内的使用说明，并配合自检排查问题。", table_desc);
        lbl.ForeColor = Color.FromArgb(0x22, 0x66, 0xff);
        #endregion

        #region 配置：队员顺序
        string[] playerDescriptions = { "坦克", "治疗", "近战位", "远程位" };
        form.AddPartyGroup(" 队员顺序 ", new PartyListPanel(playerDescriptions));
        #endregion

        // 统一清理并运行
        Application.OpenForms.OfType<GameConfigForm>().ToList().ForEach(f => f.Close());
        form.Run();
    }

    [STAThread]
    public static void Start()
    {
        try
        {
            Application.OpenForms.OfType<GameConfigForm>().ToList().ForEach(f => f.Close());
            Thread staThread = new Thread(new ThreadStart(RunConfigForm));
            staThread.SetApartmentState(ApartmentState.STA);
            staThread.Start();
        }
        catch (Exception ex)
        {
            MessageBox.Show("用户配置表单运行错误：\n" + ex, Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Windows.Forms;
using Triggernometry.Core;

List<TreeNode> FindTargetNodes(IEnumerable<TreeNode> nodes, Func<TreeNode, bool> filter)
{
    var result = new List<TreeNode>();
    foreach (var node in nodes)
    {
        if (!node.Checked) continue;

        if (filter(node))
        {
            result.Add(node);
        }
        else if (node.Nodes.Count > 0)
        {
            result.AddRange(FindTargetNodes(node.Nodes.Cast<TreeNode>(), filter));
        }
    }
    return result;
}

var detectName = "异闻迷宫宝宝椅";
var allNodes = RealPlugin.Instance.ui.treeView1.Nodes.Cast<TreeNode>();
var matchedNodes = FindTargetNodes(allNodes, node => node.Tag is Folder f && f.Name.Contains(detectName));

if (matchedNodes.Count > 1)
{
    MessageBox.Show($"检测到多个 “{detectName}” 分组，你需要关闭至仅有一个启用。", detectName, MessageBoxButtons.OK, MessageBoxIcon.Warning);
}

