Action.ExecScriptExpression:
using System;
using System.Collections.Generic;
using System.Globalization;
using System.Linq;
using Triggernometry;
using Triggernometry.Core;
using Triggernometry.Core.Variables;
using Triggernometry.Expressions.Maths;
using Triggernometry.Expressions.String.Utils;
using Triggernometry.PluginBridges;
using static Triggernometry.Core.Scripting.ScriptHelper;

RealPlugin.Instance.RegisterNamedCallback("V6a1_拉球1_MarkSafeSpots", new Action<object, string>(
    (_, varName) => {
        Storage.Remove("V6a1_FuzzBall1");
        V6a1_FuzzBall1_Analyzer.Instance.MarkSafeSpots(varName);
    }
), null);

RealPlugin.Instance.RegisterNamedCallback("V6a1_拉球1_CheckPlayerSafe", new Action<object, string>(
    (_, varName) => V6a1_FuzzBall1_Analyzer.Instance.CheckPlayerSafe(varName)
), null);

public static class V6a1_FuzzBall1_Analyzer
{
    public static V6a1_FuzzBall1 Instance
    {
        get
        {
            V6a1_FuzzBall1 instance;
            lock (Storage)
            {
                if (Storage.TryGetValue("V6a1_FuzzBall1", out object o) && o is V6a1_FuzzBall1 existingInstance)
                {
                    return existingInstance;
                }
            }
            V6a1_FuzzBall1.Log("未初始化，创建新 V6a1_FuzzBall1_Analyzer 实例");
            instance = new V6a1_FuzzBall1();
            lock (Storage)
            {
                Storage["V6a1_FuzzBall1"] = instance;
            }
            return instance;
        }
    }
}

public class V6a1_FuzzBall1
{
    public List<FuzzBall> FuzzBalls { get; set; }
    public FuzzBall Boss { get; set; }
    public bool IsBossIce { get; set; }
    public bool IsCardinal { get; set; }

    public static string DebugChannel = GetDictVariable(true, "V&C_cfg").GetValue("cnlDebug").ToString();

    public static void Log(string msg) => RealPlugin.Instance.InvokeNamedCallback("command", $"/{DebugChannel} \n{msg}");

    public V6a1_FuzzBall1()
    {
        IsBossIce = GetScalarVariable(false, "V6a1_泡_type") == "冰";
        IsCardinal = GetScalarVariable(false, "V6a1_拉球1_is正") == "1";
        FuzzBalls = GetListVariable(false, "V6a1_拉球1_rawData").Values.Select(v => FuzzBall.FromRawData(v.ToString())).ToList();
        Boss = new FuzzBall(IsBossIce ? FuzzBallType.冰 : FuzzBallType.风, new Vector3(0, 0), -Math.PI);
    }

    public List<SafeSpot> GetPossibleSafeSpots()
    {
        // 西北象限的所有可能安全点
        var spots = new List<SafeSpot>();
        if (IsBossIce)
        {
            if (IsCardinal)
                spots.Add(new SafeSpot(new Vector3(-5.5, -5.5), 0.3));
            else
                spots.Add(new SafeSpot(new Vector3(-6.3, -6.3), 1.1));
            spots.Add(new SafeSpot(new Vector3(-11.3, -11.3), 1.25));
            spots.Add(new SafeSpot(new Vector3(-18.5, -12.0), 1.25));
            spots.Add(new SafeSpot(new Vector3(-12.0, -18.5), 1.25));
        }
        else
        {   // 半径 2.5 中心圆的斜向八等分点
            spots.Add(new SafeSpot(new Vector3(-2.31, -0.96), 1.25));
            spots.Add(new SafeSpot(new Vector3(-0.96, -2.31), 1.25));
        }
        // 经过对映得到全场的可能安全点
        var allSpots = new List<SafeSpot>();
        foreach (var spot in spots)
        {
            var hFlip = spot.HFlip();
            allSpots.Add(spot);
            allSpots.Add(hFlip);
            allSpots.Add(hFlip.VFlip());
            allSpots.Add(spot.VFlip());
        }
        return allSpots;
    }

    public void CheckPlayerSafe(string varName)
    {
        VariableDictionary me = BridgeFFXIV.GetIdEntity(BridgeFFXIV.PlayerHexId);
        Vector3 myRelPos = new Vector3(
            double.Parse(me.GetValue("x").ToString(), NumberStyles.Float, CultureInfo.InvariantCulture),
            double.Parse(me.GetValue("y").ToString(), NumberStyles.Float, CultureInfo.InvariantCulture)
        ).AbsToRel();
        bool isSafe = Boss.IsRelPosSafe(myRelPos) && FuzzBalls.All(ball => ball.IsRelPosSafe(myRelPos));
        SetScalarVariable(false, varName, isSafe ? 1 : 0);
    }

    public void MarkSafeSpots(string varName)
    {
        List<SafeSpot> possibleSafeSpots = GetPossibleSafeSpots();
        Log("possibleSafeSpots: \n" + string.Join("\n", possibleSafeSpots.Select(spot => spot.RelCenter).ToList()));

        List<SafeSpot> safeSpots = possibleSafeSpots.Where(spot =>
            FuzzBalls.All(ball => spot.IsSafeFrom(ball))
        ).ToList();

        var spots = safeSpots.Select(s => s.RelCenter.ToString()).ToList();
        string command =
            $"action: place \n" +
            $"center: {Vector3.Center} \n" +
            $"1: {(spots.Count >= 1 ? spots[0] : "fakeclear")} \n" +
            $"2: {(spots.Count >= 2 ? spots[1] : "fakeclear")} \n" +
            $"3: {(spots.Count >= 3 ? spots[2] : "fakeclear")} \n" +
            $"4: {(spots.Count >= 4 ? spots[3] : "fakeclear")} \n" +
            $"A: {(spots.Count >= 5 ? spots[4] : "fakeclear")} \n" +
            $"B: {(spots.Count >= 6 ? spots[5] : "fakeclear")} \n" +
            $"C: {(spots.Count >= 7 ? spots[6] : "fakeclear")} \n" +
            $"D: {(spots.Count >= 8 ? spots[7] : "fakeclear")}";

        string tts;
        if (spots.Count >= 2)
            tts = "去任意标点";
        else if (spots.Count == 0)
            tts = "没救了，等死吧";
        else
        {
            double x = safeSpots[0].RelCenter.X;
            double y = safeSpots[0].RelCenter.Y;
            if (Math.Abs(x) < 5 && Math.Abs(y) < 5)
                tts = "去中心壹号点";
            else
            {
                tts = $"去{new string[] { "左上", "左下", "右下", "右上" }[(int)MathParser.RoundvecFunction(new double[] { x, y, -4 })]}壹号点";
            }
        }

        SetScalarVariable(false, varName, tts);
        RealPlugin.Instance.InvokeNamedCallback("AdvWm", command);
        Log(command);
    }
}

public struct Vector3
{
    public double X;
    public double Y;
    public double Z;

    public static Vector3 Center = new Vector3(-335, -155, 471);

    public Vector3(double x, double y, double z = 0) { X = x; Y = y; Z = z; }

    public Vector3 HFlip() => new Vector3(-X, Y, Z);
    public Vector3 VFlip() => new Vector3(X, -Y, Z);
    public Vector3 RelToAbs()
        => new Vector3(X + Center.X, Y + Center.Y, Z + Center.Z);
    public Vector3 AbsToRel()
        => new Vector3(X - Center.X, Y - Center.Y, Z - Center.Z);

    public override string ToString() => $"{X:F2}, {Y:F2}, {Z:F2}";
}

public class SafeSpot
{
    public Vector3 RelCenter { get; set; }
    public double CheckRadius { get; set; }

    private List<Vector3> _spotsToCheck;
    public List<Vector3> SpotsToCheck
    {
        get
        {
            if (_spotsToCheck == null)
            {
                _spotsToCheck = new List<Vector3>();
                double θ = -Math.PI;
                for (int i = 0; i < 8; i++)
                {
                    _spotsToCheck.Add(new Vector3(RelCenter.X + CheckRadius * Math.Cos(θ), RelCenter.Y + CheckRadius * Math.Sin(θ)));
                    θ += Math.PI / 4;
                }
            }
            return _spotsToCheck;
        }
    }

    public SafeSpot(Vector3 relCenter, double checkRadius)
    {
        RelCenter = relCenter;
        CheckRadius = checkRadius;
    }

    public SafeSpot HFlip() => new SafeSpot(RelCenter.HFlip(), CheckRadius);
    public SafeSpot VFlip() => new SafeSpot(RelCenter.VFlip(), CheckRadius);

    public bool IsSafeFrom(FuzzBall ball)
    {
        bool isSafe = SpotsToCheck.All(spot => ball.IsRelPosSafe(spot));
        if (!isSafe)
            V6a1_FuzzBall1.Log($"{ball} => ({RelCenter}): " + (isSafe ? "安全" : "危险"));
        return isSafe;
    }

}

public enum FuzzBallType
{
    风, 冰, 电
}

public class FuzzBall
{
    public FuzzBallType Type;
    public Vector3 RelPos;
    public double Heading;

    public FuzzBall(FuzzBallType type, Vector3 relPos, double heading)
    {
        Type = type; RelPos = relPos; Heading = heading;
    }

    /// <param name="rawData">原始数据 VariableList 中的数据，如："风:x:y:z:h" </param>
    public static FuzzBall FromRawData(string rawData)
    {
        string[] rawDataArray = rawData.Trim().Split(':');
        ArgHelper.CheckArgCount("5", rawDataArray.Length, "绒球数据", rawData);
        if (Enum.TryParse(rawDataArray[0], out FuzzBallType type) &&
            double.TryParse(rawDataArray[1], NumberStyles.Float, CultureInfo.InvariantCulture, out double x) &&
            double.TryParse(rawDataArray[2], NumberStyles.Float, CultureInfo.InvariantCulture, out double y) &&
            double.TryParse(rawDataArray[3], NumberStyles.Float, CultureInfo.InvariantCulture, out double z) &&
            double.TryParse(rawDataArray[4], NumberStyles.Float, CultureInfo.InvariantCulture, out double h))
        {
            return new FuzzBall(type, new Vector3(x, y, z).AbsToRel(), h);
        }
        else
        {
            throw new ArgumentException($"绒球数据 \"{rawData}\"中的数据无法解析。");
        }
    }

    public bool IsRelPosSafe(Vector3 relPos)
    {
        bool isSafe;
        switch (Type)
        {
            case FuzzBallType.电:
                {
                    double θ = Math.Atan2(relPos.X - RelPos.X, relPos.Y - RelPos.Y) - Heading - Math.PI;
                    int dir8 = (int)MathParser.RoundirFunction(new double[] { θ, 8 });
                    isSafe = dir8 % 2 == 0;
                    break;
                }
            case FuzzBallType.冰:
                {
                    double distanceH = MathParser.ProjectHeightFunction(new double[] { RelPos.X, RelPos.Y, Heading, relPos.X, relPos.Y });
                    double distanceV = MathParser.ProjectHeightFunction(new double[] { RelPos.X, RelPos.Y, Heading + Math.PI / 2, relPos.X, relPos.Y });
                    isSafe = distanceH > 5 && distanceV > 5;
                    break;
                }
            case FuzzBallType.风:
                {
                    double distance = MathParser.DistanceFunction(new double[] { RelPos.X, RelPos.Y, relPos.X, relPos.Y });
                    isSafe = distance < 5;
                    break;
                }
            default: throw new Exception($"Unknown FuzzBallType: {Type}");
        }
        return isSafe;
    }

    public override string ToString() => $"{Type}球 @ ({RelPos.X:F2}, {RelPos.Y:F2}), {Heading:F3}";
}

