Action.ExecScriptExpression:
using System;
using System.Globalization;
using Triggernometry.Core;
using Triggernometry.Core.Scripting;
void V6c3_炸弹安全区_AdvWm(object o, string s)
{
    int dir10 = int.Parse(ScriptHelper.GetScalarVariable(false, "V6c3_炸弹_dir10").ToString());
    string dθraw = ScriptHelper.GetScalarVariable(false, "V6c3_炸弹_dθ")?.ToString() ?? "0";
    double dθ = double.Parse(dθraw, NumberStyles.Float, CultureInfo.InvariantCulture);
    bool isMidSafe = ScriptHelper.GetScalarVariable(false, "V6c3_炸弹_isMidSafe").ToString().Trim() == "1";

    string command;
    if (!isMidSafe)
    {
        command =
        $@"
            action: arc
            center: -200, 0, -200
            θ: {dir10} * pi/5 - {dθ}
            r: 13.25
            waymarks: 4321DCBA
        ";
        if (dir10 % 2 == 0) // 小钝角：过中心 dir10偶 南边105
        {
            command += "dθ: 105°";
        }
        else // 小锐角：过中心 dir10奇 南边176
        {
            command += "dθ: 176°";
        }
    }
    else
    {
        command =
        $@"
            action: place
            center: -200, 0, -200
            θ: {dir10} * pi/5 - pi - {dθ}
        ";
        if (dir10 % 2 == 0) // 大钝角：不过中心 dir10偶
        {
            command +=
            @"
                A: -1.32, -1.81
                B:  1.32, -1.81
                C: -2.80,  2.00
                D:  2.80,  2.00
                1: -5.37,  5.17
                2:  5.37,  5.17
                3: -8.78,  7.43
                4:  8.78,  7.43
            ";
        }
        else // 大锐角：不过中心 dir10奇
        {
            command +=
            @"
                A:   0.00,  1.75
                B:   5.31,  1.65
                C:   0.00, -2.25
                D:  -5.31,  1.65
                1:   9.25,  5.49
                2:  10.66,  1.00
                3: -10.66,  1.00
                4:  -9.25,  5.49
            ";
        }
    }

    RealPlugin.Instance.InvokeNamedCallback("AdvWm", command);
}

RealPlugin.Instance.RegisterNamedCallback("V6c3_炸弹安全区_AdvWm", new Action<object, string>(V6c3_炸弹安全区_AdvWm), null);

